#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;

struct Node{
	int x,y;
}p[N];

int n,mn=2e9;
long long m,ans;

bool cmp(Node a,Node b){
	return a.x<b.x;
}

int main(){
	scanf("%d%lld",&n,&m);
	for(int i=1;i<=n;i++){
		scanf("%d%d",&p[i].x,&p[i].y);
		mn=min(mn,p[i].x+p[i].y);
	}
	sort(p+1,p+n+1,cmp);
	ans=max(ans,m/mn*2);
	long long sum=0;
	for(int i=1;i<=n;i++){
		sum+=p[i].x;
		if(sum>m)
			break; 
		ans=max(ans,(m-sum)/mn*2+i);
	}
	printf("%lld\n",ans);
	return 0;
}
